    if (!active) return;
    const parent = active.currentTurn ?? active.root;
    const tool = parent.createChild({
      name: event.toolName,
      run_type: "tool",
      inputs: { toolCallId: event.toolCallId, args: event.args },
      metadata: { toolName: event.toolName, toolCallId: event.toolCallId },
