  if (payload.input && payload.messages == null) {
    const { input, ...rest } = payload;
    return {
      messages: convertResponsesPayload(input) ?? input,
      ...rest,
    };
  }

  return payload;
};

async function startLlmRun(
  trace: TraceContext,
  parent: RunTree,
  pending: PendingLlmRun,
): Promise<RunTree> {
  const llm = parent.createChild({
    name: pending.name,
    run_type: "llm",
    inputs: convertProviderPayload(pending.payload),
    metadata: pending.metadata,
  });

  trace.currentLlm = llm;
  await safePost(llm);
